"use client";

import { FormEvent, useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { ArrowRight, BookOpenCheck, GraduationCap, LogIn, ShieldCheck, Sparkles } from "lucide-react";

import { getAccessToken, clearAccessToken, setAccessToken } from "@/lib/dev-auth";
import { getMe, login, UserSummary } from "@/lib/api";
import { BrandMark } from "@/components/BrandMark";
import { ChatbotHero } from "@/components/ChatbotHero";

function dashboardForRole(user: UserSummary) {
  if (user.role === "ADMIN") return "/admin/dashboard";
  if (user.role === "TEACHER") return "/teacher/dashboard";
  if (user.role === "STUDENT") return "/student/dashboard";
  return "/parent/dashboard";
}

export default function LoginPage() {
  const router = useRouter();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    const token = getAccessToken();
    if (!token) return;
    void getMe(token)
      .then((user) => router.push(dashboardForRole(user)))
      .catch(() => clearAccessToken());
  }, [router]);

  async function onSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setBusy(true);
    setError("");
    try {
      const session = await login(email, password);
      setAccessToken(session.access_token);
      router.push(dashboardForRole(session.user));
    } catch (error) {
      setError(error instanceof Error ? error.message : "Không thể đăng nhập");
    } finally {
      setBusy(false);
    }
  }

  return (
    <main className="relative min-h-screen overflow-hidden px-4 py-8 text-ink sm:px-6 lg:px-8">
      <div className="absolute left-[-9rem] top-[-9rem] h-[30rem] w-[30rem] rounded-full bg-brand-100/80 blur-3xl" />
      <div className="absolute bottom-[-12rem] right-[-9rem] h-[34rem] w-[34rem] rounded-full bg-gold/15 blur-3xl" />

      <section className="relative mx-auto grid min-h-[calc(100vh-4rem)] max-w-7xl items-center gap-8">
        <div className="overflow-hidden rounded-[2.5rem] border border-white/75 bg-white/86 shadow-glow backdrop-blur lg:grid lg:grid-cols-[1fr_0.82fr]">
          <div className="relative flex min-h-[580px] flex-col justify-between overflow-hidden bg-gradient-to-br from-brand-dark via-brand to-[#30a047] p-6 text-white sm:p-10">
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_18%_16%,rgba(255,255,255,0.22),transparent_20rem),radial-gradient(circle_at_90%_82%,rgba(246,191,38,0.18),transparent_18rem)]" />
            <div className="relative flex items-center justify-between gap-4">
              <BrandMark className="rounded-3xl bg-white/95 p-2 shadow-soft" />
              <span className="hidden rounded-full bg-white/14 px-4 py-2 text-sm font-black text-mint ring-1 ring-white/20 sm:inline-flex">AI Learning Companion</span>
            </div>

            <div className="relative grid gap-8 py-10 lg:grid-cols-[1fr_auto] lg:items-center">
              <div className="max-w-2xl">
                <span className="mb-5 inline-flex items-center gap-2 rounded-full bg-white/15 px-4 py-2 text-sm font-bold text-mint ring-1 ring-white/20">
                  <Sparkles className="h-4 w-4" aria-hidden="true" />
                  Pippo đồng hành học tiếng Anh
                </span>
                <h1 className="text-4xl font-black leading-tight tracking-tight sm:text-5xl lg:text-6xl">
                  Một cổng học tập rõ ràng, thân thiện và thông minh.
                </h1>
                <p className="mt-5 max-w-xl text-base leading-8 text-white/82">
                  Theo dõi tiến độ, nhận phản hồi giáo viên và trò chuyện với Pippo AI trong một giao diện hiện đại cho phụ huynh, giáo viên, học viên và quản trị.
                </p>
              </div>
              <div className="mx-auto lg:mx-0">
                <ChatbotHero size="lg" />
              </div>
            </div>

            <div className="relative grid gap-3 text-sm font-semibold text-white/88 sm:grid-cols-3">
              <span className="rounded-2xl border border-white/15 bg-white/10 p-4 backdrop-blur">Phân quyền theo vai trò</span>
              <span className="rounded-2xl border border-white/15 bg-white/10 p-4 backdrop-blur">Báo cáo học tập rõ ràng</span>
              <span className="rounded-2xl border border-white/15 bg-white/10 p-4 backdrop-blur">Pippo AI hỗ trợ 24/7</span>
            </div>
          </div>

          <div className="flex items-center bg-white/92 p-6 sm:p-10">
            <div className="w-full">
              <div className="mb-8">
                <div className="mb-4 inline-flex items-center gap-2 rounded-full bg-brand-50 px-4 py-2 text-sm font-black text-brand ring-1 ring-brand-100">
                  <ShieldCheck className="h-4 w-4" aria-hidden="true" />
                  Đăng nhập an toàn
                </div>
                <h2 className="text-3xl font-black tracking-tight text-ink">Chào mừng quay lại</h2>
                <p className="mt-2 text-sm leading-6 text-slate-500">Nhập tài khoản được trung tâm cấp để truy cập dashboard học tập.</p>
              </div>

              <form onSubmit={onSubmit} className="space-y-4">
                <label className="block text-sm font-bold text-ink">
                  Email
                  <input
                    className="portal-input mt-2 w-full"
                    type="email"
                    value={email}
                    onChange={(event) => setEmail(event.target.value)}
                    autoComplete="email"
                    placeholder="name@pts.edu.vn"
                    required
                  />
                </label>
                <label className="block text-sm font-bold text-ink">
                  Mật khẩu
                  <input
                    className="portal-input mt-2 w-full"
                    type="password"
                    value={password}
                    onChange={(event) => setPassword(event.target.value)}
                    autoComplete="current-password"
                    placeholder="••••••••"
                    required
                  />
                </label>
                <button
                  className="inline-flex min-h-12 w-full items-center justify-center gap-2 rounded-2xl bg-brand px-5 text-base font-black text-white shadow-portal hover:bg-brand-dark disabled:opacity-60"
                  disabled={busy}
                >
                  <LogIn className="h-5 w-5" aria-hidden="true" />
                  {busy ? "Đang đăng nhập..." : "Đăng nhập"}
                  <ArrowRight className="h-5 w-5" aria-hidden="true" />
                </button>
              </form>
              {error ? <p className="mt-4 rounded-2xl border border-coral/30 bg-coral/10 p-4 text-sm font-semibold text-coral">{error}</p> : null}

              <div className="mt-8 rounded-3xl border border-brand-100 bg-brand-50/55 p-4 shadow-sm">
                <p className="mb-3 flex items-center gap-2 text-sm font-black text-ink">
                  <BookOpenCheck className="h-4 w-4 text-brand" aria-hidden="true" />
                  Lối tắt thử nghiệm
                </p>
                <div className="grid gap-2 sm:grid-cols-2">
                  {[
                    ["Phụ huynh", "/parent/dashboard"],
                    ["Giáo viên", "/teacher/dashboard"],
                    ["Quản trị", "/admin/dashboard"],
                    ["Học viên", "/student/dashboard"],
                  ].map(([label, href]) => (
                    <button
                      key={href}
                      type="button"
                      onClick={() => router.push(href)}
                      className="inline-flex min-h-10 items-center justify-center gap-2 rounded-2xl border border-brand-100 bg-white px-3 text-sm font-bold text-brand shadow-sm hover:border-brand-200 hover:bg-brand-50"
                    >
                      <GraduationCap className="h-4 w-4" aria-hidden="true" />
                      {label}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>
    </main>
  );
}

