export function ZaloQrSection({ studentId, compact = false }: { studentId: string; compact?: boolean }) {
  const [qrData, setQrData] = useState<StudentZaloQrResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    async function loadQr() {
      const token = getAccessToken();
      if (!token) return;
      try {
        setQrData(await getStudentZaloQr(studentId, token));
      } catch {
        setQrData(null);
      } finally {
        setLoading(false);
      }
    }
    void loadQr();
  }, [studentId]);

  useEffect(() => {
    if (!qrData || qrData.connected || !qrData.session_token) return;
    const token = getAccessToken();
    if (!token) return;
    const timer = setInterval(async () => {
      try {
        const updated = await getStudentZaloQr(studentId, token);
        setQrData(updated);
        if (updated.connected) clearInterval(timer);
      } catch {
        // ignore polling errors
      }
    }, 3000);
    return () => clearInterval(timer);
  }, [studentId, qrData?.connected, qrData?.session_token]);

  const shellClass = compact
    ? "rounded-[2rem] border border-brand-100 bg-white p-5 shadow-soft sm:p-6"
    : "rounded-lg border border-ink/10 bg-white p-4 shadow-panel";

  if (loading) {
    return (
      <section className={shellClass}>
        <p className="text-sm text-slate-500">Đang tải QR Zalo...</p>
      </section>
    );
  }

  if (!qrData) {
    return (
      <section className={shellClass}>
        <p className="text-sm text-coral">Không thể tải mã QR Zalo.</p>
      </section>
    );
  }

  if (qrData.connected) {
    return (
      <section className={shellClass}>
        <div className="flex items-center gap-2">
          <QrCode className="h-4 w-4 text-leaf" aria-hidden="true" />
          <h3 className="text-sm font-black">Liên kết Zalo</h3>
        </div>
        <div className="mt-3 space-y-1 text-sm">
          <p className="font-semibold text-leaf">Đã liên kết</p>
          {qrData.zalo_display_name ? <p className="text-slate-600">{qrData.zalo_display_name}</p> : null}
        </div>
      </section>
    );
  }

  return (
    <section className={shellClass}>
      <div className="flex items-center gap-2">
        <QrCode className="h-4 w-4 text-leaf" aria-hidden="true" />
        <h3 className="text-sm font-black">Liên kết Zalo</h3>
      </div>
      <p className="mt-2 text-xs leading-5 text-slate-500">
        Quét QR để mở chat Zalo với {qrData.bot_display_name || "bot trung tâm"}, sau đó gửi mã liên kết bên dưới.
      </p>
      {qrData.qr_code_url ? (
        <img
          alt="QR mở chat Zalo Bot"
          src={qrData.qr_code_url}
          className={`mx-auto mt-3 rounded bg-brand-50 object-contain p-2 ${compact ? "h-56 w-56" : "h-48 w-48"}`}
        />
      ) : (
        <div className={`mx-auto mt-3 flex items-center justify-center rounded bg-brand-50 p-4 text-center text-xs leading-5 text-coral ${compact ? "h-56 w-56" : "h-48 w-48"}`}>
          {qrData.error_message || "Bot Zalo chưa sẵn sàng. Admin cần đăng nhập Zalo bot trước."}
        </div>
      )}
      {qrData.linking_message ? (
        <div className="mt-3 rounded-2xl border border-brand-100 bg-brand-50/60 p-3 text-sm">
          <p className="text-xs font-black uppercase tracking-wide text-slate-500">Tin nhắn cần gửi trong Zalo</p>
          <p className="mt-1 break-all font-mono text-base font-black text-ink">{qrData.linking_message}</p>
          <button
            type="button"
            className="mt-2 inline-flex min-h-9 items-center justify-center rounded-full border border-brand-200 bg-white px-3 text-xs font-black text-brand"
            onClick={async () => {
              await navigator.clipboard.writeText(qrData.linking_message || "");
              setCopied(true);
              window.setTimeout(() => setCopied(false), 1500);
            }}
          >
            {copied ? "Đã sao chép" : "Sao chép mã"}
          </button>
        </div>
      ) : null}
      {qrData.deep_link_url ? (
        <a
          href={qrData.deep_link_url}
          target="_blank"
          rel="noreferrer"
          className="mt-3 inline-flex w-full items-center justify-center gap-2 rounded-full border border-brand-200 bg-white px-3 py-2 text-sm font-black text-brand"
        >
          <Link2 className="h-4 w-4" aria-hidden="true" />
          Mở Zalo và gửi mã
        </a>
      ) : null}
      {!qrData.connected && qrData.session_token ? (
        <p className="mt-3 text-center text-xs text-slate-500">Đang chờ phụ huynh gửi mã trong Zalo...</p>
      ) : null}
    </section>
  );
}

