          <Metric icon={TrendingUp} label="Ky nang" value={String(Object.keys(progress.skills).length)} detail="Ky nang co du lieu" />
        </div>
      </section>

      <section className="relative overflow-hidden rounded-4xl border border-brand-400/30 bg-gradient-to-br from-brand-dark via-brand to-brand-400 p-5 text-white shadow-portal sm:p-6">
