        </Link>
      </section>

      <ZaloQrSection studentId={student.id} compact />

      <section className="portal-section">
        <div className="mb-5 flex items-center justify-between gap-3">
          <div>
            <span className="portal-badge">Progress Track</span>
            <h2 className="mt-2 text-heading-2">Diem ky nang tieng Anh</h2>
