              <div key={skill} className="portal-card">
                <div className="flex items-center justify-between gap-3 text-body">
                  <span className="font-bold">{skill}</span>
                  <StatusPill label={score.latest < 70 ? "Can luyen them" : "Dang on"} tone={score.latest < 70 ? "watch" : "good"} />
                </div>
                <div className="mt-3 grid grid-cols-2 gap-3 text-body">
                  <div>
                    <p className="text-ink-muted">Trung binh</p>
                    <p className="font-bold text-ink">{score.average}%</p>
                  </div>
                  <div>
                    <p className="text-ink-muted">Gan nhat</p>
                    <p className="font-bold text-ink">{score.latest}%</p>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>

      <section className="portal-section lg:col-span-2">
        <h2 className="mb-4 text-heading-2">Nhan xet gan day cua giao vien</h2>
        {feedback.length === 0 ? (
          <p className="rounded-xl bg-muted p-4 text-body text-ink-muted">Chua co nhan xet giao vien.</p>
        ) : (
          <div className="grid gap-4 md:grid-cols-2">
            {feedback.map((item) => (
              <article key={item.id} className="portal-card">
                <div className="mb-3 flex items-center justify-between gap-3">
                  <p className="text-body font-bold text-ink">{item.teacher_name}</p>
                  <p className="rounded-full bg-muted px-3 py-1 text-caption font-bold text-ink-muted">{new Date(item.created_at).toLocaleDateString("vi-VN")}</p>
                </div>
                <p className="text-body italic text-ink-muted">&ldquo;{item.comment}&rdquo;</p>
              </article>
            ))}
          </div>
        )}
      </section>
    </div>
  );
}

function weakestSkill(skills: StudentDashboardResponse["progress"]["skills"]) {
  const entries = Object.entries(skills);
  if (!entries.length) return null;
  const [skill, score] = entries.sort((a, b) => a[1].latest - b[1].latest)[0];
  return `${skill} can chu y nhat (${score.latest}%)`;
}

