      <span className="mb-3 grid h-9 w-9 place-items-center rounded-lg bg-brand-100 text-brand">
        <Icon className="h-4 w-4" aria-hidden="true" />
      </span>
      <p className="text-caption font-bold text-ink-muted">{label}</p>
      <p className="mt-1 text-heading-3 text-ink">{value}</p>
      <p className="mt-1 text-caption text-ink-muted">{detail}</p>
    </div>
  );
}

